import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useColorScheme } from 'react-native';

type Theme = 'light' | 'dark' | 'system';

interface ThemeContextType {
  theme: Theme;
  activeTheme: 'light' | 'dark';
  setTheme: (theme: Theme) => void;
  colors: typeof lightColors;
}

const THEME_STORAGE_KEY = '@staff_app_theme';

const lightColors = {
  primary: '#E31C5F',
  primaryDark: '#D1114D',
  background: '#FFFFFF',
  backgroundGray: '#F7F7F7',
  text: '#222222',
  textSecondary: '#717171',
  border: '#DDDDDD',
  success: '#00A699',
  error: '#FF5A5F',
  white: '#FFFFFF',
  card: '#FFFFFF',
  inputBackground: '#F7F7F7',
  shadow: '#000000',
};

const darkColors = {
  primary: '#FF4D7F',
  primaryDark: '#E31C5F',
  background: '#121212',
  backgroundGray: '#1E1E1E',
  text: '#FFFFFF',
  textSecondary: '#A0A0A0',
  border: '#333333',
  success: '#00D4C4',
  error: '#FF6B6B',
  white: '#FFFFFF',
  card: '#1E1E1E',
  inputBackground: '#2C2C2C',
  shadow: '#FFFFFF',
};

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const systemColorScheme = useColorScheme();
  const [theme, setThemeState] = useState<Theme>('system');
  const [isLoading, setIsLoading] = useState(true);

  // Load saved theme on mount
  useEffect(() => {
    loadTheme();
  }, []);

  const loadTheme = async () => {
    try {
      const savedTheme = await AsyncStorage.getItem(THEME_STORAGE_KEY);
      if (savedTheme && (savedTheme === 'light' || savedTheme === 'dark' || savedTheme === 'system')) {
        setThemeState(savedTheme as Theme);
      }
    } catch (error) {
      console.error('Failed to load theme preference:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const setTheme = async (newTheme: Theme) => {
    try {
      await AsyncStorage.setItem(THEME_STORAGE_KEY, newTheme);
      setThemeState(newTheme);
    } catch (error) {
      console.error('Failed to save theme preference:', error);
    }
  };

  // Determine the active theme based on preference
  const activeTheme: 'light' | 'dark' = React.useMemo(() => {
    if (theme === 'system') {
      return systemColorScheme === 'dark' ? 'dark' : 'light';
    }
    return theme;
  }, [theme, systemColorScheme]);

  const colors = activeTheme === 'dark' ? darkColors : lightColors;

  if (isLoading) {
    return null; // Or a loading screen
  }

  return (
    <ThemeContext.Provider value={{ theme, activeTheme, setTheme, colors }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
}

